package org.apache.commons.csv;

import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintAndEscapeTest {

    private CSVFormat csvFormatDefault;
    private Method printAndEscapeMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        csvFormatDefault = CSVFormat.DEFAULT;
        printAndEscapeMethod = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        printAndEscapeMethod.setAccessible(true);
    }

    @Test
    void testPrintAndEscape_noSpecialChars() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "simpletext";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, input.length(), out);

        assertEquals("simpletext", out.toString());
    }

    @Test
    void testPrintAndEscape_withDelimiter() throws IOException, InvocationTargetException, IllegalAccessException {
        // Delimiter is COMMA for DEFAULT
        String input = "abc,def";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, input.length(), out);

        // The comma should be escaped with escape char (DOUBLE_QUOTE_CHAR '"')
        // So output expected: abc"",""def
        // Actually, the method replaces delimiter with escape + delimiter char
        // So output should be: abc"","def  but delimiter is ',' so it outputs: abc"","def
        // The escape char is DOUBLE_QUOTE_CHAR (")
        // So the comma is replaced by " + ','

        // So output should be: abc","def
        assertEquals("abc\"\,def", out.toString());
    }

    @Test
    void testPrintAndEscape_withEscapeChar() throws IOException, InvocationTargetException, IllegalAccessException {
        // Escape char is DOUBLE_QUOTE_CHAR '"'
        String input = "abc\"def";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, input.length(), out);

        // The quote char should be escaped with escape char (")
        // So output: abc""def
        assertEquals("abc\"\"def", out.toString());
    }

    @Test
    void testPrintAndEscape_withCR() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "line1\rline2";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, input.length(), out);

        // CR is replaced with escape + 'r'
        // So output: line1\rline2 but \r is replaced with "r" with escape char prepended
        // So output: line1"rline2
        assertEquals("line1\"rline2", out.toString());
    }

    @Test
    void testPrintAndEscape_withLF() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "line1\nline2";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, input.length(), out);

        // LF is replaced with escape + 'n'
        // So output: line1"nline2
        assertEquals("line1\"nline2", out.toString());
    }

    @Test
    void testPrintAndEscape_partialInput() throws IOException, InvocationTargetException, IllegalAccessException {
        // Test with offset and length parameters
        String input = "abc,def\"ghi\njkl\r";
        StringBuilder out = new StringBuilder();

        // Extract substring "def\"ghi\nj"
        int offset = 4;
        int len = 8;

        printAndEscapeMethod.invoke(csvFormatDefault, input, offset, len, out);

        // input substring = def"ghi\nj
        // Escape chars: " and \n
        // So output: def""ghi"nj
        assertEquals("def\"\"ghi\"nj", out.toString());
    }

    @Test
    void testPrintAndEscape_emptyInput() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, 0, out);

        assertEquals("", out.toString());
    }

    @Test
    void testPrintAndEscape_singleEscapeChar() throws IOException, InvocationTargetException, IllegalAccessException {
        // Input is just the escape char
        String input = "\"";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormatDefault, input, 0, 1, out);

        // Escape char should be doubled
        assertEquals("\"\"", out.toString());
    }
}
